  let cur = nums[0];  // 以当前元素结尾的最大子数组和
  for (let i = 1; i < nums.length; i++) {
    cur = Math.max(nums[i], cur + nums[i]); // 接着累加 or 重新起头
    best = Math.max(best, cur);
  }
